/*MON_GET_PKG_CACHE_STMT_START*/SELECT CURRENT TIMESTAMP AS TS,MEMBER, PLANID, HEX(EXECUTABLE_ID) EXECUTABLE_ID, PACKAGE_NAME, STMT_TEXT, EFFECTIVE_ISOLATION, STMTID, SEMANTIC_ENV_ID, ACTIVE_SORTS_TOP, SORT_HEAP_TOP, SORT_SHRHEAP_TOP, NUM_EXEC_WITH_METRICS, COORD_STMT_EXEC_TIME, TOTAL_ACT_TIME, TOTAL_CPU_TIME, TOTAL_ACT_WAIT_TIME, LOCK_WAIT_TIME, LOG_DISK_WAIT_TIME, LOG_BUFFER_WAIT_TIME, POOL_WRITE_TIME, POOL_READ_TIME, DIRECT_WRITE_TIME, DIRECT_READ_TIME, ROWS_MODIFIED, ROWS_READ, ROWS_RETURNED, TOTAL_SORTS, SORT_OVERFLOWS, TOTAL_SECTION_TIME, TOTAL_SECTION_SORT_TIME, POOL_DATA_L_READS, POOL_INDEX_L_READS, POOL_DATA_P_READS, POOL_INDEX_P_READS, POOL_DATA_WRITES, POOL_INDEX_WRITES, POOL_TEMP_DATA_P_READS, POOL_TEMP_INDEX_P_READS, DIRECT_READ_REQS, DIRECT_WRITE_REQS, IDA_SEND_WAIT_TIME, IDA_RECV_WAIT_TIME, CF_WAIT_TIME, RECLAIM_WAIT_TIME, TOTAL_EXTENDED_LATCH_WAIT_TIME, LOCK_WAIT_TIME_GLOBAL, PREFETCH_WAIT_TIME, DIAGLOG_WRITE_WAIT_TIME, AUDIT_FILE_WRITE_WAIT_TIME, AUDIT_SUBSYSTEM_WAIT_TIME, FCM_RECV_WAIT_TIME, FCM_SEND_WAIT_TIME, FCM_MESSAGE_RECV_WAIT_TIME, FCM_MESSAGE_SEND_WAIT_TIME, FCM_TQ_RECV_WAIT_TIME, FCM_TQ_SEND_WAIT_TIME, EVMON_WAIT_TIME, POOL_COL_L_READS, POOL_COL_P_READS, TOTAL_COL_TIME, COMM_EXIT_WAIT_TIME, COL_SYNOPSIS_ROWS_INSERTED, EXT_TABLE_RECV_WAIT_TIME, EXT_TABLE_SEND_WAIT_TIME, LOB_PREFETCH_WAIT_TIME, FED_WAIT_TIME FROM TABLE (MON_GET_PKG_CACHE_STMT( NULL, NULL, NULL, -2) ) WHERE STMT_TEXT NOT LIKE 'CALL DBMS_ALERT.SLEEP%' AND STMT_TEXT NOT LIKE '%/* DB2MON */%';
